import json,sys
d=json.load(sys.stdin)
for p in d.get('projects',[]):
  name=p['path'].split('/')[-1]
  for fw in p.get('frameworks',[]):
    for pkg in fw.get('topLevelPackages',[]):
      print(f'{name}: {pkg[\"id\"]} {pkg.get(\"resolvedVersion\",\"\")}')
"

